+private enum CleanupModelArtifactStatus {
+    case missing
+    case valid
+    case invalid
+}
+
+private enum CleanupModelArtifactValidator {
+    private static let ggufMagicHeader = Data("GGUF".utf8)
+
+    static func isValidGGUFFile(at url: URL, fileManager: FileManager) -> Bool {
+        guard
+            let attributes = try? fileManager.attributesOfItem(atPath: url.path),
+            let fileSize = attributes[.size] as? NSNumber,
+            fileSize.intValue >= ggufMagicHeader.count,
+            let handle = try? FileHandle(forReadingFrom: url)
+        else {
+            return false
+        }
+
+        defer {
+            try? handle.close()
+        }
+
+        guard let header = try? handle.read(upToCount: ggufMagicHeader.count) else {
+            return false
+        }
+
+        return header == ggufMagicHeader
+    }
+}
+
+private enum CleanupModelDownloadClient {
+    static func url(for model: CleanupModelDescriptor) -> URL {
+        URL(string: "https://huggingface.co/\(model.huggingFaceRepository)/resolve/main/\(model.fileName)?download=true")!
+    }
+
+    static func download(
+        from sourceURL: URL,
+        to destinationURL: URL,
+        updateProgress: @escaping @Sendable (Double) -> Void
+    ) async throws {
+        let parentDirectory = destinationURL.deletingLastPathComponent()
+        try FileManager.default.createDirectory(at: parentDirectory, withIntermediateDirectories: true)
+
+        var progressObservation: NSKeyValueObservation?
+        let temporaryURL: URL = try await withCheckedThrowingContinuation { continuation in
+            let task = URLSession.shared.downloadTask(with: sourceURL) { url, response, error in
+                if let error {
+                    continuation.resume(throwing: error)
+                    return
+                }
+
+                guard
+                    let url,
+                    let httpResponse = response as? HTTPURLResponse,
+                    httpResponse.statusCode / 100 == 2
+                else {
+                    continuation.resume(throwing: CleanupModelDownloadError.invalidResponse)
+                    return
+                }
+
+                continuation.resume(returning: url)
+            }
+
+            progressObservation = task.progress.observe(\.fractionCompleted) { progress, _ in
+                updateProgress(progress.fractionCompleted)
+            }
+
+            task.resume()
+        }
+
+        _ = progressObservation
+        if FileManager.default.fileExists(atPath: destinationURL.path) {
+            try FileManager.default.removeItem(at: destinationURL)
+        }
+        try FileManager.default.moveItem(at: temporaryURL, to: destinationURL)
+    }
+}
+
+private enum CleanupModelDownloadError: Error {
+    case invalidResponse
+}
